import json
import os
import subprocess
import tempfile
import pytest

AC_UID = "ac3_score_inject_reads_jsonl_not_agentscores"
AC_TYPE = "data"


def test_AC3():
    """
    GIVEN: logs/lifecycle.jsonl contains a baseline entry for ba with new_score=70 AND agent-scores.json contains a different score (e.g. 40) for ba
    WHEN:  bash scripts/score-inject.sh --agent ba is invoked
    THEN:  stdout contains [Range: 61-80] (Senior Craftsman range for score 70), not the range for score 40
    """
    repo = "/dev/shm/dev-workspace/dot-claude"
    fd_lc, tmp_lifecycle = tempfile.mkstemp(suffix=".jsonl", prefix="test-ac3-")
    try:
        # Seed lifecycle with ba at score 70 (Senior Craftsman, range 61-80)
        seed = {
            "ts": "2026-05-25T00:00:00Z", "agent": "ba", "event": "score_baseline_import",
            "prev_score": 70, "new_score": 70, "delta": 0, "unclamped_score": 70,
            "actor": "migration", "reason": "seed"
        }
        with os.fdopen(fd_lc, "w") as f:
            f.write(json.dumps(seed) + "\n")

        result = subprocess.run(
            ["bash", "scripts/score-inject.sh",
             "--agent", "ba",
             "--lifecycle-file", tmp_lifecycle],
            capture_output=True, text=True, cwd=repo,
        )
        assert result.returncode == 0, f"score-inject.sh failed: {result.stderr}"
        assert "[Range: 61-80]" in result.stdout, (
            f"Expected [Range: 61-80] (score 70) in output, got: {result.stdout[:200]}"
        )
        assert "[Range: 21-40]" not in result.stdout, (
            "Score-inject should not use agent-scores.json range [Range: 21-40]"
        )
    finally:
        try:
            os.unlink(tmp_lifecycle)
        except OSError:
            pass
